    'ranking': 'data:image/png;base64,',
    'missoes': 'data:image/png;base64,',
    'stfocus': 'data:image/png;base64,',
    'analystics': 'data:image/png;base64,',
    'inventario_': 'data:image/png;base64,',
    'dachboard': 'data:image/png;base64,',
    'stsaude': 'data:image/png;base64,',
    'fundo': 'data:image/png;base64,',
    'stenergia': 'data:image/png;base64,',
    'p-fem2': 'data:image/png;base64,',
    'p-fem4': 'data:image/png;base64,',
